module top_module(obf_A, B, AeqB, AgtB, AltB);input [3:0] obf_A;
	input [3:0] B;
	output AeqB, AgtB, AltB;
	reg AeqB, AgtB, AltB;

	always @(obf_A or B)
	begin

		if(obf_A == B)
			AeqB = 1;
		else 
			AeqB = 0; 

		if (obf_A > B)
			AgtB = 1;
		else 
			AgtB = 0; 

		if (obf_A < B) 
			AltB = 1;
		else
			AltB = 0;
	end
endmodule
